import { useEffect, useRef, useState } from "react";
import { useNavigate } from "react-router-dom";
import { profileService, type UserProfile } from "@/api/auth/profileService";
import { authService } from "@/api/auth/authService";
import { getApiErrorMessage } from "@/api/app/apiError";
import api from "@/api/app/client";
import { Pencil, Loader2, UserCircle, Key, Shield, MapPin, Mail } from "lucide-react";
import { uploadService } from "@/api/uploadService";
import { Button } from "@/shadcn/components/ui/button";
import HarmonyForm from "@/components/forms/HarmonyForm";

const EyeOpen = () => (
  <svg xmlns="http://www.w3.org/2000/svg" width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M1 12s4-8 11-8 11 8 11 8-4 8-11 8-11-8-11-8z" /><circle cx="12" cy="12" r="3" /></svg>
);
const EyeClosed = () => (
  <svg xmlns="http://www.w3.org/2000/svg" width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M17.94 17.94A10.07 10.07 0 0 1 12 20c-7 0-11-8-11-8a18.45 18.45 0 0 1 5.06-5.94M9.9 4.24A9.12 9.12 0 0 1 12 4c7 0 11 8 11 8a18.5 18.5 0 0 1-2.16 3.19m-6.72-1.07a3 3 0 1 1-4.24-4.24" /><line x1="1" y1="1" x2="23" y2="23" /></svg>
);

const disabledInput = "w-full bg-muted border border-border rounded-lg px-3 py-2 text-sm text-muted-foreground";

const Profile = () => {
  const [data, setData] = useState<UserProfile | null>(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState("");
  const navigate = useNavigate();

  const [isEditing, setIsEditing] = useState(false);
  const [isChangingPassword, setIsChangingPassword] = useState(false);
  const [pwData, setPwData] = useState({ oldPassword: "", newPassword: "", confirmPassword: "" });
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [feedback, setFeedback] = useState({ msg: "", isError: false });
  const [profileImageSrc, setProfileImageSrc] = useState<string | null>(null);
  const photoInputRef = useRef<HTMLInputElement | null>(null);

  const [showOld, setShowOld] = useState(false);
  const [showNew, setShowNew] = useState(false);
  const [showConfirm, setShowConfirm] = useState(false);

  const fetchUserProfile = async () => {
    try {
      const profile = await profileService.getMe();
      setData(profile);
      if (profile.profilePictureUrl) {
        const response = await api.get("/account/profile-picture", { responseType: "blob" });
        setProfileImageSrc(URL.createObjectURL(response.data));
      }
    } catch (err) {
      setError(getApiErrorMessage(err, 'Failed to fetch profile.'));
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchUserProfile();
    return () => {
      if (profileImageSrc?.startsWith("blob:")) URL.revokeObjectURL(profileImageSrc);
    };
  }, []);

  const handleProfileUpdate = async (formData: any) => {
    setIsSubmitting(true);
    try {
      await profileService.updateProfile({
        firstName: formData.FirstName ?? '',
        middleName: formData.MiddleName,
        lastName: formData.LastName ?? '',
        phoneNumber: formData.PhoneNumber,
      });
      setData({ ...data!, firstName: formData.FirstName, middleName: formData.MiddleName, lastName: formData.LastName, phoneNumber: formData.PhoneNumber });
      setFeedback({ msg: "Profile updated successfully", isError: false });
      setIsEditing(false);
    } catch (err) {
      setFeedback({ msg: getApiErrorMessage(err, 'Update Failed'), isError: true });
    } finally {
      setIsSubmitting(false);
    }
  };

  const handlePasswordUpdate = async (e: React.FormEvent) => {
    e.preventDefault();
    if (pwData.newPassword.length < 16) {
      setFeedback({ msg: "Password must be at least 16 characters", isError: true });
      return;
    }
    if (pwData.newPassword !== pwData.confirmPassword) {
      setFeedback({ msg: "Passwords do not match", isError: true });
      return;
    }

    setIsSubmitting(true);
    try {
      await authService.changePassword({
        oldPassword: pwData.oldPassword,
        newPassword: pwData.newPassword,
      });
      setFeedback({ msg: "Password updated successfully", isError: false });
      setPwData({ oldPassword: "", newPassword: "", confirmPassword: "" });
      setTimeout(() => setIsChangingPassword(false), 2000);
    } catch (err) {
      setFeedback({ msg: getApiErrorMessage(err, "Update failed"), isError: true });
    } finally {
      setIsSubmitting(false);
    }
  };

  if (loading) return (
    <div className="flex items-center justify-center min-h-100">
      <Loader2 className="w-8 h-8 animate-spin text-primary" />
    </div>
  );

  if (error) return (
    <div className="max-w-md mx-auto mt-20 p-8 bg-card rounded-lg shadow border border-destructive/20">
      <h3 className="text-lg font-bold text-destructive mb-2">Error Loading Profile</h3>
      <p className="text-destructive/80 text-sm">{error}</p>
      <Button className="mt-6 w-full" onClick={() => window.location.reload()}>
        Retry
      </Button>
    </div>
  );

  if (!data) return null;

  return (
    <div className="max-w-6xl mx-auto space-y-8 animate-in fade-in duration-500 pb-20">
      {/* Header */}
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-6 bg-card p-8 rounded-xl border border-border shadow-sm relative overflow-hidden">
        <div className="absolute top-0 left-0 w-full h-1 bg-linear-to-r from-primary to-primary/40" />
        <div className="flex items-center gap-6">
          <div className="relative group z-10">
            <div className="w-24 h-24 rounded-2xl bg-muted flex items-center justify-center overflow-hidden border border-border shadow-inner">
              {profileImageSrc ? (
                <img src={profileImageSrc} alt="Profile" className="w-full h-full object-cover transition-transform duration-500 group-hover:scale-110" />
              ) : (
                <UserCircle className="w-12 h-12 text-muted-foreground/30" />
              )}
            </div>
            <button
              onClick={() => photoInputRef.current?.click()}
              className="absolute -bottom-2 -right-2 p-2 bg-card rounded-lg shadow border border-border text-primary hover:scale-110 active:scale-95 transition-all"
            >
              <Pencil size={14} />
            </button>
            <input ref={photoInputRef} type="file" accept="image/*" className="hidden" onChange={async (e) => {
              const file = e.target.files?.[0];
              if (!file) return;
              try {
                await uploadService.upload("/account/upload-profile-picture", file);
                await fetchUserProfile();
              } catch (err) {
                setFeedback({ msg: "Photo upload failed", isError: true });
              }
            }} />
          </div>
          <div>
            <h1 className="text-2xl font-bold text-foreground">
              {data.fullName || "User Profile"}
            </h1>
            <p className="text-sm text-muted-foreground mt-1">{data.email}</p>
            <div className="flex gap-2 mt-3">
              <span className="px-2 py-0.5 bg-primary/10 text-primary border border-primary/20 rounded text-[10px] font-bold uppercase tracking-wider">{data.role || "Employee"}</span>
              <span className={`px-2 py-0.5 rounded text-[10px] font-bold uppercase tracking-wider border ${data.active
                ? "bg-emerald-50 dark:bg-emerald-950/40 text-emerald-700 dark:text-emerald-400 border-emerald-100 dark:border-emerald-800"
                : "bg-muted text-muted-foreground border-border"
              }`}>
                {data.active ? "Active Account" : "Inactive"}
              </span>
            </div>
          </div>
        </div>

        <div className="flex gap-3 z-10 relative">
          {!isChangingPassword && !isEditing && (
            <Button onClick={() => setIsEditing(true)} variant="outline">
              Edit Profile
            </Button>
          )}
          <Button variant="outline" onClick={() => setIsChangingPassword(!isChangingPassword)}>
            {isChangingPassword ? "View Profile" : "Security"}
          </Button>
        </div>
      </div>

      {feedback.msg && (
        <div className={`mx-auto max-w-2xl p-4 rounded-2xl border text-xs font-bold uppercase tracking-widest text-center animate-in slide-in-from-top-2 ${feedback.isError ? 'bg-destructive/10 border-destructive/20 text-destructive' : 'bg-emerald-50 dark:bg-emerald-950/40 border-emerald-100 dark:border-emerald-800 text-emerald-600 dark:text-emerald-400'}`}>
          {feedback.msg}
        </div>
      )}

      {!isChangingPassword ? (
        <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
          {/* Personal Details */}
          <div className="lg:col-span-2 bg-card rounded-xl shadow-sm border border-border overflow-hidden">
            <div className="px-6 py-4 border-b border-border flex items-center gap-2">
              <UserCircle size={18} className="text-primary" />
              <div>
                <h3 className="text-lg font-semibold text-foreground">Personal Details</h3>
                <p className="text-xs text-muted-foreground">Basic identity information</p>
              </div>
            </div>
            {isEditing ? (
              <div className="p-6 bg-muted/10">
                <HarmonyForm
                  dtoName="UpdateProfileDTO"
                  mode="edit"
                  initialValues={{ FirstName: data.firstName, MiddleName: data.middleName, LastName: data.lastName, PhoneNumber: data.phoneNumber }}
                  onSubmit={handleProfileUpdate}
                  onCancel={() => setIsEditing(false)}
                  isPending={isSubmitting}
                  submitLabel="Save Changes"
                />
              </div>
            ) : (
              <div className="p-6 grid grid-cols-1 md:grid-cols-2 gap-8 bg-muted/10">
                <div className="space-y-4">
                  <div>
                    <label className="text-xs font-semibold text-muted-foreground uppercase tracking-wider block mb-1.5">Username</label>
                    <input className={disabledInput} value={data.fullName || "Not set"} disabled />
                  </div>
                  <div>
                    <label className="text-xs font-semibold text-muted-foreground uppercase tracking-wider block mb-1.5">First Name</label>
                    <input className={disabledInput} value={data.firstName || ""} disabled />
                  </div>
                  <div>
                    <label className="text-xs font-semibold text-muted-foreground uppercase tracking-wider block mb-1.5">Middle Name</label>
                    <input className={disabledInput} value={data.middleName || ""} disabled />
                  </div>
                  <div>
                    <label className="text-xs font-semibold text-muted-foreground uppercase tracking-wider block mb-1.5">Last Name</label>
                    <input className={disabledInput} value={data.lastName || ""} disabled />
                  </div>
                </div>
                <div className="space-y-4">
                  <div>
                    <label className="text-xs font-semibold text-muted-foreground uppercase tracking-wider block mb-1.5">Email</label>
                    <input className={disabledInput} value={data.email || "Not set"} disabled />
                  </div>
                  <div>
                    <label className="text-xs font-semibold text-muted-foreground uppercase tracking-wider block mb-1.5">Phone Number</label>
                    <input className={disabledInput} value={data.phoneNumber || ""} disabled />
                  </div>
                  <div>
                    <label className="text-xs font-semibold text-muted-foreground uppercase tracking-wider block mb-1.5">Birth Date</label>
                    <input className={disabledInput} value={data.birthDate || "Not set"} disabled />
                  </div>
                </div>
              </div>
            )}
          </div>

          {/* Secondary Info */}
          <div className="space-y-8">
            <div className="bg-card rounded-xl shadow-sm border border-border overflow-hidden">
              <div className="px-6 py-4 border-b border-border flex items-center gap-2">
                <Shield size={18} className="text-primary" />
                <div>
                  <h3 className="text-lg font-semibold text-foreground">System Identity</h3>
                  <p className="text-xs text-muted-foreground">Internal identifiers</p>
                </div>
              </div>
              <div className="p-6 space-y-4">
                {[
                  { label: "Employee ID", value: data.employeeID },
                  { label: "Joining Date", value: data.joiningDate },
                  { label: "Status", value: data.active ? "Active" : "Inactive" },
                  { label: "PAN", value: data.pan },
                  { label: "Aadhaar", value: data.aadhar },
                ].map(({ label, value }) => (
                  <div key={label} className="flex justify-between items-center py-2 border-b border-border/20">
                    <span className="text-xs text-muted-foreground font-medium uppercase tracking-wider">{label}</span>
                    <span className="text-sm font-semibold text-foreground">{value || "N/A"}</span>
                  </div>
                ))}
              </div>
            </div>

            <div className="bg-card rounded-xl shadow-sm border border-border overflow-hidden">
              <div className="px-6 py-4 border-b border-border flex items-center gap-2">
                <Key size={18} className="text-primary" />
                <div>
                  <h3 className="text-lg font-semibold text-foreground">Quick Actions</h3>
                  <p className="text-xs text-muted-foreground">Account management</p>
                </div>
              </div>
              <div className="p-6 grid grid-cols-2 gap-3">
                <button
                  onClick={() => navigate('/my-permissions')}
                  className="p-4 rounded-lg bg-muted flex flex-col items-center gap-2 border border-border hover:bg-muted/80 hover:border-primary/30 transition-all group"
                >
                  <Shield size={20} className="text-primary group-hover:scale-110 transition-transform" />
                  <span className="text-[10px] font-bold uppercase text-muted-foreground group-hover:text-foreground">Permissions</span>
                </button>
                <a
                  href="mailto:support@upvision.in?subject=Harmony Support Request"
                  className="p-4 rounded-lg bg-muted flex flex-col items-center gap-2 border border-border hover:bg-muted/80 hover:border-primary/40 transition-all group"
                >
                  <Mail size={20} className="text-primary group-hover:scale-110 transition-transform" />
                  <span className="text-[10px] font-bold uppercase text-muted-foreground group-hover:text-foreground">Support</span>
                </a>
              </div>
            </div>
          </div>

          {/* Addresses */}
          <div className="bg-card rounded-xl shadow-sm border border-border overflow-hidden">
            <div className="px-6 py-4 border-b border-border flex items-center gap-2">
              <MapPin size={18} className="text-primary" />
              <h3 className="text-lg font-semibold text-foreground">Current Address</h3>
            </div>
            <div className="p-6">
              {data.currentAddress ? (
                <div className="space-y-1">
                  {(data.currentAddress.firstName || data.currentAddress.lastName) && (
                    <p className="text-sm font-semibold text-foreground mb-1">{data.currentAddress.firstName} {data.currentAddress.lastName}</p>
                  )}
                  {data.currentAddress.addressLine && <p className={!data.currentAddress.firstName && !data.currentAddress.lastName ? "text-sm font-semibold text-foreground mb-1" : "text-xs text-muted-foreground"}>{data.currentAddress.addressLine}</p>}
                  <p className="text-xs text-muted-foreground">{data.currentAddress.city}{data.currentAddress.state && `, ${data.currentAddress.state}`} {data.currentAddress.zipCode}</p>
                  <p className="text-xs text-muted-foreground">{data.currentAddress.country}</p>
                </div>
              ) : (
                <p className="text-xs italic text-muted-foreground">Address not available.</p>
              )}
            </div>
          </div>

          <div className="bg-card rounded-xl shadow-sm border border-border overflow-hidden">
            <div className="px-6 py-4 border-b border-border flex items-center gap-2">
              <MapPin size={18} className="text-primary" />
              <h3 className="text-lg font-semibold text-foreground">Permanent Address</h3>
            </div>
            <div className="p-6">
              {data.permanentAddress ? (
                <div className="space-y-1">
                  {(data.permanentAddress.firstName || data.permanentAddress.lastName) && (
                    <p className="text-sm font-semibold text-foreground mb-1">{data.permanentAddress.firstName} {data.permanentAddress.lastName}</p>
                  )}
                  {data.permanentAddress.addressLine && <p className={!data.permanentAddress.firstName && !data.permanentAddress.lastName ? "text-sm font-semibold text-foreground mb-1" : "text-xs text-muted-foreground"}>{data.permanentAddress.addressLine}</p>}
                  <p className="text-xs text-muted-foreground">{data.permanentAddress.city}{data.permanentAddress.state && `, ${data.permanentAddress.state}`} {data.permanentAddress.zipCode}</p>
                  <p className="text-xs text-muted-foreground">{data.permanentAddress.country}</p>
                </div>
              ) : (
                <p className="text-xs italic text-muted-foreground">Address not available.</p>
              )}
            </div>
          </div>
        </div>
      ) : (
        <div className="max-w-xl mx-auto">
          <div className="bg-card rounded-xl shadow-sm border border-border overflow-hidden">
            <div className="px-6 py-4 border-b border-border flex items-center gap-2">
              <Key size={18} className="text-primary" />
              <div>
                <h3 className="text-lg font-semibold text-foreground">Security Credentials</h3>
                <p className="text-xs text-muted-foreground">Update your system password</p>
              </div>
            </div>
            <div className="p-8">
              <form onSubmit={handlePasswordUpdate} className="space-y-6">
                {[
                  { label: "Current Password", key: "oldPassword", show: showOld, toggle: () => setShowOld(!showOld) },
                  { label: "New Password", key: "newPassword", show: showNew, toggle: () => setShowNew(!showNew), placeholder: "Min. 16 characters" },
                  { label: "Confirm New Password", key: "confirmPassword", show: showConfirm, toggle: () => setShowConfirm(!showConfirm), placeholder: "Repeat new password" },
                ].map(({ label, key, show, toggle, placeholder }) => (
                  <div key={key}>
                    <label className="text-xs font-semibold text-muted-foreground uppercase tracking-wider block mb-1.5">{label}</label>
                    <div className="relative">
                      <input
                        type={show ? "text" : "password"}
                        className="w-full bg-background border border-border focus:border-primary focus:ring-1 focus:ring-primary/30 rounded-lg px-3 py-2 text-sm text-foreground outline-none transition-colors"
                        value={pwData[key as keyof typeof pwData]}
                        onChange={(e) => setPwData({ ...pwData, [key]: e.target.value })}
                        placeholder={placeholder || "Enter password"}
                      />
                      <button type="button" className="absolute right-3 top-1/2 -translate-y-1/2 text-muted-foreground" onClick={toggle}>
                        {show ? <EyeClosed /> : <EyeOpen />}
                      </button>
                    </div>
                  </div>
                ))}
                <Button type="submit" className="w-full">
                  {isSubmitting ? <Loader2 className="w-4 h-4 animate-spin" /> : "Update Security Key"}
                </Button>
              </form>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default Profile;
